sys_variable_value.value:
(function(outputs, steps, params, stepResult, assertEqual) {
    // 1. Specify your custom table name here
    var tableName = 'x_1839224_chroma_0_chromatech_sold_products'; 
    
    // 2. Query the sys_db_object table to check the 'super_class' (Parent)
    var grTable = new GlideRecord('sys_db_object');
    grTable.addQuery('name', tableName);
    grTable.query();

    if (grTable.next()) {
        // super_class is empty if the table does not extend anything
        if (grTable.super_class.nil()) {
            stepResult.setOutputMessage("Success: Table '" + tableName + "' is a standalone table and does not extend any other table.");
            stepResult.setSuccess();
            return true;
        } else {
            var parentTable = grTable.super_class.getDisplayValue();
            stepResult.setOutputMessage("Failure: Table '" + tableName + "' extends '" + parentTable + "'. Expected no parent.");
            stepResult.setFailed();
            return false;
        }
    } else {
        stepResult.setOutputMessage("Error: Table '" + tableName + "' was not found in the system.");
        stepResult.setFailed();
        return false;
    }

})(outputs, steps, params, stepResult, assertEqual);
